```go
// staticIndex is built once from generated models_static_gen.go data.
var (
    staticOnce  sync.Once
    staticList  []ModelInfo
    staticByID  map[ModelID]ModelInfo
    staticByProv map[Provider][]ModelInfo
    staticByFam  map[string][]ModelInfo
)

func ensureIndex() {
    staticOnce.Do(func() {
        staticList = staticModels() // from models_static_gen.go
        staticByID = make(map[ModelID]ModelInfo, len(staticList))
        staticByProv = make(map[Provider][]ModelInfo)
        staticByFam = make(map[string][]ModelInfo)
        for _, m := range staticList {
            staticByID[m.ID] = m
            staticByProv[m.Provider] = append(staticByProv[m.Provider], m)
            if m.Family != "" {
                staticByFam[m.Family] = append(staticByFam[m.Family], m)
            }
        }
    })
}

// StaticModels returns the compiled-in model registry (~110 models).
func StaticModels() []ModelInfo {
    ensureIndex()
    out := make([]ModelInfo, len(staticList))
    copy(out, staticList)
    return out
}

// LookupModel finds a model by exact ID in the static registry.
func LookupModel(id ModelID) (ModelInfo, bool) {
    ensureIndex()
    m, ok := staticByID[id]
    return m, ok
}

// ModelsByProvider returns all static models from a given provider.
func ModelsByProvider(p Provider) []ModelInfo {
    ensureIndex()
    src := staticByProv[p]
    out := make([]ModelInfo, len(src))
    copy(out, src)
    return out
}

// ModelsByFamily returns all static models in a given family.
func ModelsByFamily(family string) []ModelInfo {
    ensureIndex()
    src := staticByFam[family]
    out := make([]ModelInfo, len(src))
    copy(out, src)
    return out
}
